Script.script:
tic_timer = tic_timer or {}
tic_timer.configs = tic_timer.configs or { dbug = false, on = true, tic_is_early = true, tic_is_late = false, aggro_is_exact = false, num_tics = -1, aggro_pulse = -1, tic_length = 61.000, tic_length_std_dev = 0.5, tic_warning = 7.0, show_aggros = false }
tic_timer.stopwatch = tic_timer.stopwatch or createStopWatch(false)
tic_timer.temp_timers = tic_timer.temp_timers or {}
tic_timer.mob_triggers = tic_timer.mob_triggers or {}
function tic_timer:reset() --preserve some values local debug = self.configs.dbug local warning = self.configs.tic_warning local aggros = self.configs.show_aggros
self.configs = { dbug = debug, on = true, tic_is_early = true, tic_is_late = false, aggro_is_exact = false, num_tics = -1, aggro_pulse = -1, tic_length = 61.000, tic_length_std_dev = 0.5, tic_warning = warning, show_aggros = aggros }
self.tic_history = {61.0, size = 1}
resetStopWatch(self.stopwatch) for name, id in pairs(self.temp_timers) do killTimer(id) self.temp_timers[name] = nil end for name, id in pairs(self.mob_triggers) do killTimer(id) self.mob_triggers[name] = nil end end
